// Extract Claude response from nested structure
const responseContent = $json.content[0].text;

// Parse JSON from Claude
let icp;
try {
  icp = JSON.parse(responseContent);
} catch(e) {
  // If Claude wrapped in markdown backticks, extract it
  const jsonMatch = responseContent.match(/```json\n?(.*?)\n?```/s);
  if (jsonMatch) {
    icp = JSON.parse(jsonMatch[1]);
  } else if (responseContent.match(/^\{/)) {
    // Try raw object
    icp = JSON.parse(responseContent);
  } else {
    throw new Error('Invalid JSON from Claude: ' + responseContent.substring(0, 200));
  }
}

// Validate required top-level fields
const requiredFields = [
  'icp_name',
  'demographics',
  'firmographics',
  'psychographics',
  'daily_pain_points',
  'watering_holes',
  'buying_triggers',
  'budget_range',
  'decision_criteria',
  'common_objections'
];

for (const field of requiredFields) {
  if (icp[field] === undefined || icp[field] === null) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Validate demographics object
const demoFields = ['title', 'experience_level', 'education'];
for (const field of demoFields) {
  if (!icp.demographics[field]) {
    throw new Error(`demographics missing field: ${field}`);
  }
}

// Validate firmographics object
const firmFields = ['company_size', 'revenue_range', 'growth_stage', 'industry_focus'];
for (const field of firmFields) {
  if (!icp.firmographics[field]) {
    throw new Error(`firmographics missing field: ${field}`);
  }
}

// Validate psychographics object
if (!icp.psychographics.values || !Array.isArray(icp.psychographics.values) || icp.psychographics.values.length === 0) {
  throw new Error('psychographics.values must be non-empty array');
}
if (!icp.psychographics.goals || !Array.isArray(icp.psychographics.goals) || icp.psychographics.goals.length === 0) {
  throw new Error('psychographics.goals must be non-empty array');
}
if (!icp.psychographics.fears || !Array.isArray(icp.psychographics.fears) || icp.psychographics.fears.length === 0) {
  throw new Error('psychographics.fears must be non-empty array');
}

// Validate daily_pain_points array
if (!Array.isArray(icp.daily_pain_points) || icp.daily_pain_points.length < 5) {
  throw new Error(`Expected minimum 5 pain points, got ${icp.daily_pain_points.length}`);
}

for (let i = 0; i < icp.daily_pain_points.length; i++) {
  if (!icp.daily_pain_points[i] || icp.daily_pain_points[i].trim().length === 0) {
    throw new Error(`Pain point ${i + 1} is empty`);
  }
}

// Validate watering_holes array
if (!Array.isArray(icp.watering_holes) || icp.watering_holes.length < 3) {
  throw new Error(`Expected minimum 3 watering holes, got ${icp.watering_holes.length}`);
}

for (let i = 0; i < icp.watering_holes.length; i++) {
  if (!icp.watering_holes[i] || icp.watering_holes[i].trim().length === 0) {
    throw new Error(`Watering hole ${i + 1} is empty`);
  }
}

// Validate buying_triggers array
if (!Array.isArray(icp.buying_triggers) || icp.buying_triggers.length < 3) {
  throw new Error(`Expected minimum 3 buying triggers, got ${icp.buying_triggers.length}`);
}

for (let i = 0; i < icp.buying_triggers.length; i++) {
  if (!icp.buying_triggers[i] || icp.buying_triggers[i].trim().length === 0) {
    throw new Error(`Buying trigger ${i + 1} is empty`);
  }
}

// Validate budget_range object
if (!icp.budget_range.min || !icp.budget_range.max || !icp.budget_range.decision_timeframe) {
  throw new Error('budget_range missing min, max, or decision_timeframe');
}

// Validate decision_criteria array
if (!Array.isArray(icp.decision_criteria) || icp.decision_criteria.length < 4) {
  throw new Error(`Expected minimum 4 decision criteria, got ${icp.decision_criteria.length}`);
}

for (let i = 0; i < icp.decision_criteria.length; i++) {
  if (!icp.decision_criteria[i] || icp.decision_criteria[i].trim().length === 0) {
    throw new Error(`Decision criterion ${i + 1} is empty`);
  }
}

// Validate common_objections array
if (!Array.isArray(icp.common_objections) || icp.common_objections.length < 3) {
  throw new Error(`Expected minimum 3 objections, got ${icp.common_objections.length}`);
}

for (let i = 0; i < icp.common_objections.length; i++) {
  const objection = icp.common_objections[i];
  if (!objection.objection || !objection.counter_argument) {
    throw new Error(`Objection ${i + 1} missing objection or counter_argument`);
  }
}

return icp;

